import { notFound } from "next/navigation";
import { prisma } from "@/lib/prisma";
import Link from "next/link";

type SeriesPageProps = {
  params: Promise<{
    seriesKey: string;
  }>;
};

export default async function SeriesPage({ params }: SeriesPageProps) {
  // Grab seriesKey from params
  const { seriesKey } = await params;

  const series = await prisma.eventSeries.findUnique({
    where: { slugBase: seriesKey },
    include: {
      events: {
        orderBy: { dueAt: "asc" },
      },
    },
  });

  if (!series) {
    notFound();
  }

  return (
    <main className="min-h-screen bg-zinc-950 text-zinc-100">
      <section className="mx-auto flex w-full max-w-5xl flex-col gap-8 px-6 py-16">
        
        {/* HERO SECTION */}
        <div className="rounded-3xl border border-zinc-800 bg-gradient-to-br from-zinc-900 via-zinc-900 to-emerald-950/30 p-10 shadow-xl">
          <p className="mb-3 inline-block rounded-full border border-emerald-500/40 bg-emerald-500/10 px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] text-emerald-200">
            Series Hub
          </p>
          <h1 className="text-4xl font-black tracking-tight text-zinc-50 sm:text-5xl">
            {series.title}
          </h1>
          {series.description ? (
            <p className="mt-4 max-w-3xl text-base leading-relaxed text-zinc-300 sm:text-lg">
              {series.description}
            </p>
          ) : (
            <p className="mt-4 max-w-3xl text-sm text-zinc-400">
              Track the complete timeline and upcoming dates for this series below.
            </p>
          )}
        </div>

        {/* EVENTS LIST */}
        <section>
          <h2 className="mb-4 text-sm font-black uppercase tracking-[0.25em] text-zinc-400">
            Official Timeline
          </h2>

          {series.events.length === 0 ? (
            <div className="rounded-2xl border border-zinc-800 bg-zinc-900/60 p-6 text-sm text-zinc-400">
              No events found for this series yet. Check back soon.
            </div>
          ) : (
            <div className="grid gap-4">
              {series.events.map((event) => {
                // Generate the correct URL path based on your site's structure
                const eventUrl = `/${event.category.toLowerCase()}/${event.slug}`;

                return (
                  <Link href={eventUrl} key={event.id} className="block group">
                    <article className="flex items-center justify-between rounded-2xl border border-zinc-800 bg-zinc-900/50 p-6 transition-all duration-300 hover:scale-[1.01] hover:border-emerald-500/50 hover:bg-zinc-900 hover:shadow-[0_0_20px_rgba(16,185,129,0.1)]">
                      
                      <div>
                        <h3 className="text-lg font-bold text-zinc-100 group-hover:text-emerald-400 transition-colors">
                          {event.title}
                        </h3>
                        <p className="mt-1 text-sm font-mono text-zinc-400">
                          {event.dueAt
                            ? new Date(event.dueAt).toLocaleDateString("en-US", {
                                year: "numeric",
                                month: "long",
                                day: "numeric",
                              })
                            : "Date TBA"}
                        </p>
                      </div>

                      {/* Click Indicator */}
                      <div className="text-zinc-600 group-hover:text-emerald-500 transition-colors transform group-hover:translate-x-1">
                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <path d="M5 12h14"></path>
                          <path d="m12 5 7 7-7 7"></path>
                        </svg>
                      </div>

                    </article>
                  </Link>
                );
              })}
            </div>
          )}
        </section>
      </section>
    </main>
  );
}